#!/usr/bin/env python3
"""
GitLab CI/CD Pipeline Generator

Detects project type and generates a starter .gitlab-ci.yml pipeline.
Supports: Node.js, Python, Go, Rust, Java/Maven, Docker, PHP, Ruby

Usage:
    python3 generate_pipeline.py [--type node|python|go|rust|java|docker|php|ruby|auto] [output-path]
"""

