# ── Auto-detection ─────────────────────────────────────────────────

def detect_project_type(project_dir="."):
    """Detect project type from files in the directory."""
    for project_type, config in TEMPLATES.items():
        for detect_file in config["detect_files"]:
            if os.path.isfile(os.path.join(project_dir, detect_file)):
                return project_type
    return None


def generate(project_type="auto", project_dir=".", output_path=None):
    """Generate a pipeline file."""
    if project_type == "auto":
        detected = detect_project_type(project_dir)
        if detected is None:
            print("Could not auto-detect project type.")
            print("Supported types: " + ", ".join(TEMPLATES.keys()))
            print("Use --type to specify manually.")
            sys.exit(1)
        project_type = detected
        print(f"Detected project type: {project_type}")

    if project_type not in TEMPLATES:
        print(f"Unknown project type: {project_type}")
        print(f"Supported: {', '.join(TEMPLATES.keys())}")
        sys.exit(1)

    pipeline = TEMPLATES[project_type]["pipeline"]

    if output_path is None:
        output_path = ".gitlab-ci.yml"

    output = os.path.join(project_dir, output_path)
    with open(output, "w", encoding="utf-8") as f:
        f.write(pipeline)

    print(f"Generated: {output}")
    return output


def main():
    parser = argparse.ArgumentParser(description="Generate a GitLab CI/CD pipeline")
    parser.add_argument(
        "--type",
        choices=list(TEMPLATES.keys()) + ["auto"],
        default="auto",
        help="Project type (default: auto-detect)",
    )
    parser.add_argument(
        "output",
        nargs="?",
        default=None,
        help="Output file path (default: .gitlab-ci.yml)",
    )
    args = parser.parse_args()

    generate(args.type, ".", args.output)


if __name__ == "__main__":
    main()
